scan_table_check.script:
(function (engine) {

	if (x_snc_codesanity.IsCheckApplicableToRecord())
	{
		if (x_snc_devtools.IsNowAssistAIAgentsInstalled() == false)
		{
			return;
		}

		var nCustomToolCount = 0;

		var grAgentTool = new GlideRecord('sn_aia_agent_tool_m2m');
		grAgentTool.addQuery('tool',current.tool);
		grAgentTool.query();
		while (grAgentTool.next() == true)
		{
			var grTool = x_snc_devtools.GetRecord('sn_aia_tool',grAgentTool.tool);
			if (x_snc_devtools.IsValidRecord(grTool) == true)
			{
				if (x_snc_devtools.IsOotbRecord(grTool) == false)
				{
					nCustomToolCount++;
				}
			}
		}
		if (nCustomToolCount > 1)
		{
			engine.finding.increment();
		}
	}

})(engine);
